args.sparql:
SELECT ?horse ?horseLabel ?jockey ?jockeyLabel
WHERE {
  wd:Q4600256 p:P710 ?participant .
  ?participant ps:P710 ?horse .
  ?participant pq:P3060 wd:Q6659994 .
  ?participant pq:P5317 ?jockey .
  OPTIONAL { ?horse rdfs:label ?horseLabel FILTER(lang(?horseLabel) = 'en') }
  OPTIONAL { ?jockey rdfs:label ?jockeyLabel FILTER(lang(?jockeyLabel) = 'en') }
}

SELECT ?horse ?horseLabel ?jockey ?jockeyLabel
WHERE {
  ?horse wdt:P1694 wd:Q4600256 .
  ?horse p:P1694 ?stmt .
  ?stmt ps:P1694 wd:Q4600256 .
  ?stmt pq:P5317 ?jockey .
  OPTIONAL { ?horse rdfs:label ?horseLabel FILTER(lang(?horseLabel) = 'en') }
  OPTIONAL { ?jockey rdfs:label ?jockeyLabel FILTER(lang(?jockeyLabel) = 'en') }
}
